const ZHUSHENG_99_DATA = [
{"no": 1, "displayNo": "第1籤", "level": "平", "title": "註生娘娘靈籤第1籤", "poem": ["好事從來有", "須當仔細尋", "千般無阻滯", "不用前進心"], "story": "【審慎守成】未見固定人物故事。仔細尋與不用前進心構成審慎守成的雙重勸戒。", "classicMeaning": "", "plainMeaning": "第1籤以審慎守成為核心。四句依次為好事從來有、須當仔細尋、千般無阻滯、不用前進心。整體義理是：好事雖有，必須仔細辨認，不能因表面無阻便躁進。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把好事從來有與流通占斷經營要仔細合看。就職位、合作、權責與計畫推進而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把須當仔細尋與流通占斷運途平常合看。就準備程度、評核、公平程序與臨場表現而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把千般無阻滯與流通占斷求財平合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把不用前進心與流通占斷失物緩可獲合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把好事從來有與流通占斷病難急癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "總論": "本籤以審慎守成為總軸。好事從來有先定局勢，不用前進心交代收束；流通短斷又記運途平常。因此總體評為平，關鍵不是籤名好壞，而是是否符合好事雖有，必須仔細辨認，不能因表面無阻便躁進。", "婚姻": "問婚姻時，須把千般無阻滯與流通占斷婚姻平合看。就婚約、家庭共識、責任與長期相處而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把不用前進心與流通占斷貴人緩合看。就貴人、小人、互信與溝通界線而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把好事從來有與流通占斷婚姻平合看。就雙方意願、承諾、互動與情緒安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把須當仔細尋與流通占斷行人緩合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把千般無阻滯與流通占斷田厝不吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的審慎守成脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句不用前進心下手：好事雖有，必須仔細辨認，不能因表面無阻便躁進。傳統占斷留下風水再尋，守舊無礙，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以好事從來有辨識現況、以須當仔細尋檢查限制、以千般無阻滯尋找轉機、以不用前進心設定停止或完成條件。因本籤重點是審慎守成，實際行動應符合好事雖有，必須仔細辨認，不能因表面無阻便躁進。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 2, "displayNo": "第2籤", "level": "大吉", "title": "註生娘娘靈籤第2籤", "poem": ["久雨漸初晴", "雲開見日新", "經求逢大利", "爭訟得光亨"], "story": "【雨霽更新】久雨初晴是傳統詩歌常見的否極泰來意象，重點在漸字，表示改善不是瞬間完成。", "classicMeaning": "", "plainMeaning": "第2籤以雨霽更新為核心。四句依次為久雨漸初晴、雲開見日新、經求逢大利、爭訟得光亨。整體義理是：阻滯逐步解除，事情由晦暗轉明朗。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把久雨漸初晴與流通占斷運途漸次通合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把雲開見日新與流通占斷運途漸次通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把經求逢大利與流通占斷謀財吉合看。就收入來源、成本、交易與回收風險而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把爭訟得光亨與流通占斷失物東方尋合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把久雨漸初晴與流通占斷問醫吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "總論": "本籤以雨霽更新為總軸。久雨漸初晴先定局勢，爭訟得光亨交代收束；流通短斷又記運途漸次通。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合阻滯逐步解除，事情由晦暗轉明朗。", "婚姻": "問婚姻時，須把經求逢大利與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把爭訟得光亨與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把久雨漸初晴與流通占斷婚姻吉合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把雲開見日新與流通占斷謀財吉合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把經求逢大利與流通占斷厝宅吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的雨霽更新脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句爭訟得光亨下手：阻滯逐步解除，事情由晦暗轉明朗。傳統占斷留下謀財吉，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以久雨漸初晴辨識現況、以雲開見日新檢查限制、以經求逢大利尋找轉機、以爭訟得光亨設定停止或完成條件。因本籤重點是雨霽更新，實際行動應符合阻滯逐步解除，事情由晦暗轉明朗。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 3, "displayNo": "第3籤", "level": "偏弱", "title": "註生娘娘靈籤第3籤", "poem": ["無事生煩惱", "無災恐怕侵", "相逢無利益", "不用進前心"], "story": "【疑懼自擾】連用無事、無災，說明焦慮可能放大本來不存在的危險；未見固定歷史典故。", "classicMeaning": "", "plainMeaning": "第3籤以疑懼自擾為核心。四句依次為無事生煩惱、無災恐怕侵、相逢無利益、不用進前心。整體義理是：真正阻力未必在外，而在多疑與無益往來。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把無事生煩惱與流通占斷運途未通合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把無災恐怕侵與流通占斷運途未通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把相逢無利益與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把不用進前心與流通占斷失物難尋合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把無事生煩惱與流通占斷病多端合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "總論": "本籤以疑懼自擾為總軸。無事生煩惱先定局勢，不用進前心交代收束；流通短斷又記運途未通。因此總體評為凶，關鍵不是籤名好壞，而是是否符合真正阻力未必在外，而在多疑與無益往來。", "婚姻": "問婚姻時，須把相逢無利益與流通占斷婚姻不成合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把不用進前心與流通占斷貴人暗合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把無事生煩惱與流通占斷貴人暗合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把無災恐怕侵與流通占斷求財無合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把相逢無利益與流通占斷田厝不吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的疑懼自擾脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句不用進前心下手：真正阻力未必在外，而在多疑與無益往來。傳統占斷留下凡事多疑，不如守坐，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以無事生煩惱辨識現況、以無災恐怕侵檢查限制、以相逢無利益尋找轉機、以不用進前心設定停止或完成條件。因本籤重點是疑懼自擾，實際行動應符合真正阻力未必在外，而在多疑與無益往來。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 4, "displayNo": "第4籤", "level": "平", "title": "註生娘娘靈籤第4籤", "poem": ["明月出雲端", "謀望有幾般", "寬心行正道", "不用仔細觀"], "story": "【正道見明】明月出雲是障蔽消散的傳統意象；正道與偏途的區別來自流通短斷。", "classicMeaning": "", "plainMeaning": "第4籤以正道見明為核心。四句依次為明月出雲端、謀望有幾般、寬心行正道、不用仔細觀。整體義理是：如月出雲端，守正可見局勢，偏門反而失利。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把明月出雲端與流通占斷經營穩當合看。就職位、合作、權責與計畫推進而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把謀望有幾般與流通占斷婚姻平平合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把寬心行正道與流通占斷經營穩當合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把不用仔細觀與流通占斷失物月明可覓，月暗難尋合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把明月出雲端與流通占斷醫師平合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "總論": "本籤以正道見明為總軸。明月出雲端先定局勢，不用仔細觀交代收束；流通短斷又記婚姻平平。因此總體評為平，關鍵不是籤名好壞，而是是否符合如月出雲端，守正可見局勢，偏門反而失利。", "婚姻": "問婚姻時，須把寬心行正道與流通占斷婚姻平平合看。就婚約、家庭共識、責任與長期相處而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把不用仔細觀與流通占斷貴人有合看。就貴人、小人、互信與溝通界線而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把明月出雲端與流通占斷婚姻平平合看。就雙方意願、承諾、互動與情緒安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把謀望有幾般與流通占斷婚姻平平合看。就交通、方向、應期、阻滯與人身安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把寬心行正道與流通占斷厝宅平合看。就居所、家庭安寧、田產與搬遷而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的正道見明脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句不用仔細觀下手：如月出雲端，守正可見局勢，偏門反而失利。傳統占斷留下婚姻平平，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以明月出雲端辨識現況、以謀望有幾般檢查限制、以寬心行正道尋找轉機、以不用仔細觀設定停止或完成條件。因本籤重點是正道見明，實際行動應符合如月出雲端，守正可見局勢，偏門反而失利。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 5, "displayNo": "第5籤", "level": "吉", "title": "註生娘娘靈籤第5籤", "poem": ["問病定無憂", "爭訟有官箴", "萬古澄淡月", "昨夜客回首"], "story": "【月明佳音】官箴本指官員應守的法度與勸戒；澄月與客回首共同指向公正、消息與歸來。", "classicMeaning": "", "plainMeaning": "第5籤以月明佳音為核心。四句依次為問病定無憂、爭訟有官箴、萬古澄淡月、昨夜客回首。整體義理是：病訟皆有轉機，但收益平淡，消息與月象相關。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把問病定無憂與流通占斷經營利小，淡淡而已合看。就職位、合作、權責與計畫推進而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把爭訟有官箴與流通占斷病可癒合看。就準備程度、評核、公平程序與臨場表現而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把萬古澄淡月與流通占斷經營利小，淡淡而已合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把昨夜客回首與流通占斷病可癒合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把問病定無憂與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "總論": "本籤以月明佳音為總軸。問病定無憂先定局勢，昨夜客回首交代收束；流通短斷又記凡事逢月則有佳音。因此總體評為吉，關鍵不是籤名好壞，而是是否符合病訟皆有轉機，但收益平淡，消息與月象相關。", "婚姻": "問婚姻時，須把萬古澄淡月與流通占斷婚姻成合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把昨夜客回首與流通占斷貴人來合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把問病定無憂與流通占斷婚姻成合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把爭訟有官箴與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把萬古澄淡月與流通占斷田園吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月明佳音脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句昨夜客回首下手：病訟皆有轉機，但收益平淡，消息與月象相關。傳統占斷留下凡事逢月則有佳音，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以問病定無憂辨識現況、以爭訟有官箴檢查限制、以萬古澄淡月尋找轉機、以昨夜客回首設定停止或完成條件。因本籤重點是月明佳音，實際行動應符合病訟皆有轉機，但收益平淡，消息與月象相關。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 6, "displayNo": "第6籤", "level": "大吉", "title": "註生娘娘靈籤第6籤", "poem": ["行行重行行", "與君試一程", "朱衣亦暗點", "富貴得高名"], "story": "【朱衣點頭】朱衣暗點屬文昌信仰典故，朱衣神常被視為暗中評定文章、扶助科名的神祇。後世常連結歐陽修閱卷與蘇軾應試故事，但細節主要見後代筆記與通俗說法，不宜全作正史。", "classicMeaning": "", "plainMeaning": "第6籤以朱衣點頭為核心。四句依次為行行重行行、與君試一程、朱衣亦暗點、富貴得高名。整體義理是：反覆努力後得文昌暗助，尤其有利功名考試。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把行行重行行與流通占斷求名有合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把與君試一程與流通占斷求名有合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把朱衣亦暗點與流通占斷求財有合看。就收入來源、成本、交易與回收風險而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把富貴得高名與流通占斷尋物緩合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把行行重行行與流通占斷問醫吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "總論": "本籤以朱衣點頭為總軸。行行重行行先定局勢，富貴得高名交代收束；流通短斷又記貴人暗助，運途可通。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合反覆努力後得文昌暗助，尤其有利功名考試。", "婚姻": "問婚姻時，須把朱衣亦暗點與流通占斷田園吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把富貴得高名與流通占斷貴人暗助，運途可通合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把行行重行行與流通占斷貴人暗助，運途可通合看。就雙方意願、承諾、互動與情緒安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把與君試一程與流通占斷出外吉合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把朱衣亦暗點與流通占斷田園吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的朱衣點頭脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句富貴得高名下手：反覆努力後得文昌暗助，尤其有利功名考試。傳統占斷留下試驗及第，凡事成功可望，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以行行重行行辨識現況、以與君試一程檢查限制、以朱衣亦暗點尋找轉機、以富貴得高名設定停止或完成條件。因本籤重點是朱衣點頭，實際行動應符合反覆努力後得文昌暗助，尤其有利功名考試。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 7, "displayNo": "第7籤", "level": "偏弱", "title": "註生娘娘靈籤第7籤", "poem": ["嶺上一支梅", "幾處經霜雪", "唯有暗飄香", "清秀如皎月"], "story": "【寒梅守節】梅經霜雪而暗香，是以梅喻節操、耐寒與不求人知；未見此籤固定配套人物。", "classicMeaning": "", "plainMeaning": "第7籤以寒梅守節為核心。四句依次為嶺上一支梅、幾處經霜雪、唯有暗飄香、清秀如皎月。整體義理是：經霜仍香，重點在隱忍與品格，不在眼前利益。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把嶺上一支梅與流通占斷運途未通合看。就職位、合作、權責與計畫推進而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把幾處經霜雪與流通占斷運途未通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把唯有暗飄香與流通占斷求財難合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把清秀如皎月與流通占斷尋物難合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把嶺上一支梅與流通占斷病多端合看。就病勢變化、診療、休養與危險徵象而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "總論": "本籤以寒梅守節為總軸。嶺上一支梅先定局勢，清秀如皎月交代收束；流通短斷又記運途未通。因此總體評為偏弱，關鍵不是籤名好壞，而是是否符合經霜仍香，重點在隱忍與品格，不在眼前利益。", "婚姻": "問婚姻時，須把唯有暗飄香與流通占斷求財難合看。就婚約、家庭共識、責任與長期相處而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把清秀如皎月與流通占斷求財難合看。就貴人、小人、互信與溝通界線而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把嶺上一支梅與流通占斷求財難合看。就雙方意願、承諾、互動與情緒安全而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把幾處經霜雪與流通占斷行人緩合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把唯有暗飄香與流通占斷田園不利合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的寒梅守節脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句清秀如皎月下手：經霜仍香，重點在隱忍與品格，不在眼前利益。傳統占斷留下求財難，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以嶺上一支梅辨識現況、以幾處經霜雪檢查限制、以唯有暗飄香尋找轉機、以清秀如皎月設定停止或完成條件。因本籤重點是寒梅守節，實際行動應符合經霜仍香，重點在隱忍與品格，不在眼前利益。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 8, "displayNo": "第8籤", "level": "凶", "title": "註生娘娘靈籤第8籤", "poem": ["紅火滿天炎", "干戈日日新", "若逢龍虎動", "過了見太平"], "story": "【兵火後安】龍虎可按地支辰、寅作應期，也可泛指強力衝突。流通本明確採辰寅時序解。", "classicMeaning": "", "plainMeaning": "第8籤以兵火後安為核心。四句依次為紅火滿天炎、干戈日日新、若逢龍虎動、過了見太平。整體義理是：衝突尚烈，須等辰寅所象徵的轉折時序。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把紅火滿天炎與流通占斷運途乖合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把干戈日日新與流通占斷運途乖合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把若逢龍虎動與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把過了見太平與流通占斷求財無合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把紅火滿天炎與流通占斷醫不合合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "總論": "本籤以兵火後安為總軸。紅火滿天炎先定局勢，過了見太平交代收束；流通短斷又記運途乖。因此總體評為凶，關鍵不是籤名好壞，而是是否符合衝突尚烈，須等辰寅所象徵的轉折時序。", "婚姻": "問婚姻時，須把若逢龍虎動與流通占斷婚不成合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把過了見太平與流通占斷貴人暗合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把紅火滿天炎與流通占斷貴人暗合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把干戈日日新與流通占斷求財無合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把若逢龍虎動與流通占斷田園凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的兵火後安脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句過了見太平下手：衝突尚烈，須等辰寅所象徵的轉折時序。傳統占斷留下求財無，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以紅火滿天炎辨識現況、以干戈日日新檢查限制、以若逢龍虎動尋找轉機、以過了見太平設定停止或完成條件。因本籤重點是兵火後安，實際行動應符合衝突尚烈，須等辰寅所象徵的轉折時序。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 9, "displayNo": "第9籤", "level": "吉", "title": "註生娘娘靈籤第9籤", "poem": ["一行雁虛空", "貴人節節逢", "庭前枯樹發", "祿馬又添粧"], "story": "【枯木逢春】雁象消息與遠行；枯樹再發是復甦；祿馬是命理與仕進語彙，並非僅指狀元坐騎。", "classicMeaning": "", "plainMeaning": "第9籤以枯木逢春為核心。四句依次為一行雁虛空、貴人節節逢、庭前枯樹發、祿馬又添粧。整體義理是：先難後易，貴人接續而來，舊局重新萌發。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把一行雁虛空與流通占斷經營成功合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把貴人節節逢與流通占斷久病吉合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把庭前枯樹發與流通占斷經營成功合看。就收入來源、成本、交易與回收風險而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把祿馬又添粧與流通占斷久病吉合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把一行雁虛空與流通占斷久病吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "總論": "本籤以枯木逢春為總軸。一行雁虛空先定局勢，祿馬又添粧交代收束；流通短斷又記凡事逢春更好。因此總體評為吉，關鍵不是籤名好壞，而是是否符合先難後易，貴人接續而來，舊局重新萌發。", "婚姻": "問婚姻時，須把庭前枯樹發與流通占斷婚事重姻最合合看。就婚約、家庭共識、責任與長期相處而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把祿馬又添粧與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把一行雁虛空與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把貴人節節逢與流通占斷久病吉合看。就交通、方向、應期、阻滯與人身安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把庭前枯樹發與流通占斷田厝先凶後吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的枯木逢春脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句祿馬又添粧下手：先難後易，貴人接續而來，舊局重新萌發。傳統占斷留下凡事逢春更好，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以一行雁虛空辨識現況、以貴人節節逢檢查限制、以庭前枯樹發尋找轉機、以祿馬又添粧設定停止或完成條件。因本籤重點是枯木逢春，實際行動應符合先難後易，貴人接續而來，舊局重新萌發。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 10, "displayNo": "第10籤", "level": "吉", "title": "註生娘娘靈籤第10籤", "poem": ["日出高逢上", "便照四方明", "凶星盡迴避", "散處可堪行"], "story": "【日出破暗】太陽破暗是光明、公正與凶象退散的象徵，未見固定人物典故。", "classicMeaning": "", "plainMeaning": "第10籤以日出破暗為核心。四句依次為日出高逢上、便照四方明、凶星盡迴避、散處可堪行。整體義理是：凶象退散，局面轉明，適合恢復行動。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把日出高逢上與流通占斷運途否極泰來，凡事逢凶化吉合看。就職位、合作、權責與計畫推進而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把便照四方明與流通占斷運途否極泰來，凡事逢凶化吉合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把凶星盡迴避與流通占斷求財平合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把散處可堪行與流通占斷行人至合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把日出高逢上與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "總論": "本籤以日出破暗為總軸。日出高逢上先定局勢，散處可堪行交代收束；流通短斷又記運途否極泰來，凡事逢凶化吉。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合凶象退散，局面轉明，適合恢復行動。", "婚姻": "問婚姻時，須把凶星盡迴避與流通占斷婚姻平合看。就婚約、家庭共識、責任與長期相處而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把散處可堪行與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把日出高逢上與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把便照四方明與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把凶星盡迴避與流通占斷田園吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的日出破暗脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句散處可堪行下手：凶象退散，局面轉明，適合恢復行動。傳統占斷留下運途否極泰來，凡事逢凶化吉，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以日出高逢上辨識現況、以便照四方明檢查限制、以凶星盡迴避尋找轉機、以散處可堪行設定停止或完成條件。因本籤重點是日出破暗，實際行動應符合凶象退散，局面轉明，適合恢復行動。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 11, "displayNo": "第11籤", "level": "凶", "title": "註生娘娘靈籤第11籤", "poem": ["花發春前旺", "秋風似不宜", "看來日下事", "是非莫管他"], "story": "【盛衰有時】花在春前旺、秋風不宜，直接以物候講盛衰有時；季節判斷屬本籤核心。", "classicMeaning": "", "plainMeaning": "第11籤以盛衰有時為核心。四句依次為花發春前旺、秋風似不宜、看來日下事、是非莫管他。整體義理是：春旺秋衰，時令與節奏比勉強推進更重要。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把花發春前旺與流通占斷運途乖合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把秋風似不宜與流通占斷運途乖合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把看來日下事與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把是非莫管他與流通占斷婚姻凶合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把花發春前旺與流通占斷病多端合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "總論": "本籤以盛衰有時為總軸。花發春前旺先定局勢，是非莫管他交代收束；流通短斷又記運途乖。因此總體評為凶，關鍵不是籤名好壞，而是是否符合春旺秋衰，時令與節奏比勉強推進更重要。", "婚姻": "問婚姻時，須把看來日下事與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把是非莫管他與流通占斷貴人暗合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把花發春前旺與流通占斷婚姻凶合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把秋風似不宜與流通占斷出外凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把看來日下事與流通占斷厝宅凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的盛衰有時脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句是非莫管他下手：春旺秋衰，時令與節奏比勉強推進更重要。傳統占斷留下婚姻凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以花發春前旺辨識現況、以秋風似不宜檢查限制、以看來日下事尋找轉機、以是非莫管他設定停止或完成條件。因本籤重點是盛衰有時，實際行動應符合春旺秋衰，時令與節奏比勉強推進更重要。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 12, "displayNo": "第12籤", "level": "凶", "title": "註生娘娘靈籤第12籤", "poem": ["運數未亨通", "惡星屢相逢", "祈禳吉日至", "免得落空亡"], "story": "【惡星未退】空亡是術數常用語，表示落空、失據或時位不利；不能脫離具體問事直接斷絕對凶吉。", "classicMeaning": "", "plainMeaning": "第12籤以惡星未退為核心。四句依次為運數未亨通、惡星屢相逢、祈禳吉日至、免得落空亡。整體義理是：時運尚塞，應防合謀與他人暗害，先避險。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把運數未亨通與流通占斷貴人暗合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把惡星屢相逢與流通占斷貴人暗合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把祈禳吉日至與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把免得落空亡與流通占斷貴人暗合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把運數未亨通與流通占斷病禱神合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "總論": "本籤以惡星未退為總軸。運數未亨通先定局勢，免得落空亡交代收束；流通短斷又記運未通。因此總體評為凶，關鍵不是籤名好壞，而是是否符合時運尚塞，應防合謀與他人暗害，先避險。", "婚姻": "問婚姻時，須把祈禳吉日至與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把免得落空亡與流通占斷貴人暗合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把運數未亨通與流通占斷貴人暗合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把惡星屢相逢與流通占斷出外凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把祈禳吉日至與流通占斷田園凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的惡星未退脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句免得落空亡下手：時運尚塞，應防合謀與他人暗害，先避險。傳統占斷留下貴人暗，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以運數未亨通辨識現況、以惡星屢相逢檢查限制、以祈禳吉日至尋找轉機、以免得落空亡設定停止或完成條件。因本籤重點是惡星未退，實際行動應符合時運尚塞，應防合謀與他人暗害，先避險。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 13, "displayNo": "第13籤", "level": "吉", "title": "註生娘娘靈籤第13籤", "poem": ["宜積平生福", "方應爵祿臨", "生枝桃李樹", "昨夜有喜音"], "story": "【積福得祿】積福而後爵祿，是傳統善惡報應與德福相應觀；桃李生枝亦可指子嗣、門生或成果繁衍。", "classicMeaning": "", "plainMeaning": "第13籤以積福得祿為核心。四句依次為宜積平生福、方應爵祿臨、生枝桃李樹、昨夜有喜音。整體義理是：成果須以長期善行與信用為根，不可只求速成。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把宜積平生福與流通占斷婚姻成合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把方應爵祿臨與流通占斷婚姻成合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把生枝桃李樹與流通占斷婚姻成合看。就收入來源、成本、交易與回收風險而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把昨夜有喜音與流通占斷婚姻成合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把宜積平生福與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "總論": "本籤以積福得祿為總軸。宜積平生福先定局勢，昨夜有喜音交代收束；流通短斷又記凡事宜心存行善，春天更佳。因此總體評為吉，關鍵不是籤名好壞，而是是否符合成果須以長期善行與信用為根，不可只求速成。", "婚姻": "問婚姻時，須把生枝桃李樹與流通占斷婚姻成合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把昨夜有喜音與流通占斷貴人來合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把宜積平生福與流通占斷婚姻成合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把方應爵祿臨與流通占斷婚姻成合看。就交通、方向、應期、阻滯與人身安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把生枝桃李樹與流通占斷厝宅吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的積福得祿脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句昨夜有喜音下手：成果須以長期善行與信用為根，不可只求速成。傳統占斷留下凡事宜心存行善，春天更佳，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以宜積平生福辨識現況、以方應爵祿臨檢查限制、以生枝桃李樹尋找轉機、以昨夜有喜音設定停止或完成條件。因本籤重點是積福得祿，實際行動應符合成果須以長期善行與信用為根，不可只求速成。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 14, "displayNo": "第14籤", "level": "吉", "title": "註生娘娘靈籤第14籤", "poem": ["始初明月現", "凡事盡皆通", "遠行消息近", "不久到深宮"], "story": "【月現消息】明月與遠行消息同現，象徵訊息逐步明朗；深宮可理解為目的地或正式門庭，不宜硬配人物。", "classicMeaning": "", "plainMeaning": "第14籤以月現消息為核心。四句依次為始初明月現、凡事盡皆通、遠行消息近、不久到深宮。整體義理是：訊息接近、阻礙漸通，但訴訟仍有辛苦。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把始初明月現與流通占斷運將通合看。就職位、合作、權責與計畫推進而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把凡事盡皆通與流通占斷運將通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把遠行消息近與流通占斷求財多少合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把不久到深宮與流通占斷尋物可獲合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把始初明月現與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "總論": "本籤以月現消息為總軸。始初明月現先定局勢，不久到深宮交代收束；流通短斷又記運將通。因此總體評為吉，關鍵不是籤名好壞，而是是否符合訊息接近、阻礙漸通，但訴訟仍有辛苦。", "婚姻": "問婚姻時，須把遠行消息近與流通占斷婚姻成合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把不久到深宮與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把始初明月現與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把凡事盡皆通與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把遠行消息近與流通占斷厝宅吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的月現消息脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句不久到深宮下手：訊息接近、阻礙漸通，但訴訟仍有辛苦。傳統占斷留下運將通，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以始初明月現辨識現況、以凡事盡皆通檢查限制、以遠行消息近尋找轉機、以不久到深宮設定停止或完成條件。因本籤重點是月現消息，實際行動應符合訊息接近、阻礙漸通，但訴訟仍有辛苦。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 15, "displayNo": "第15籤", "level": "凶", "title": "註生娘娘靈籤第15籤", "poem": ["在家財多有", "出路宜破財", "無人相勸保", "定是官符來"], "story": "【守家避符】官符是民間術數中官非、文書、司法糾紛的象徵；詩意明確偏向在家守成、外出破耗。", "classicMeaning": "", "plainMeaning": "第15籤以守家避符為核心。四句依次為在家財多有、出路宜破財、無人相勸保、定是官符來。整體義理是：外出、合夥與爭訟容易破財，宜收縮風險。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把在家財多有與流通占斷運途乖合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把出路宜破財與流通占斷運途乖合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把無人相勸保與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把定是官符來與流通占斷出外凶合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把在家財多有與流通占斷厝宅病合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "總論": "本籤以守家避符為總軸。在家財多有先定局勢，定是官符來交代收束；流通短斷又記運途乖。因此總體評為凶，關鍵不是籤名好壞，而是是否符合外出、合夥與爭訟容易破財，宜收縮風險。", "婚姻": "問婚姻時，須把無人相勸保與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把定是官符來與流通占斷出外凶合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把在家財多有與流通占斷婚姻凶合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把出路宜破財與流通占斷出外凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把無人相勸保與流通占斷厝宅病合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的守家避符脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句定是官符來下手：外出、合夥與爭訟容易破財，宜收縮風險。傳統占斷留下省事最好，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以在家財多有辨識現況、以出路宜破財檢查限制、以無人相勸保尋找轉機、以定是官符來設定停止或完成條件。因本籤重點是守家避符，實際行動應符合外出、合夥與爭訟容易破財，宜收縮風險。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 16, "displayNo": "第16籤", "level": "偏弱", "title": "註生娘娘靈籤第16籤", "poem": ["鐵船渡江海", "一陣風浪來", "若遇陰崖處", "舉眼見三台"], "story": "【風浪見台】鐵船本應堅固，仍遭風浪，表示僅憑自身強硬不足以保證平安；三台在星官與官祿語境中可象徵高位或貴助。", "classicMeaning": "", "plainMeaning": "第16籤以風浪見台為核心。四句依次為鐵船渡江海、一陣風浪來、若遇陰崖處、舉眼見三台。整體義理是：如鐵船遇浪，眼前多阻，貴人較晚出現。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把鐵船渡江海與流通占斷運途乖合看。就職位、合作、權責與計畫推進而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把一陣風浪來與流通占斷運途乖合看。就準備程度、評核、公平程序與臨場表現而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把若遇陰崖處與流通占斷求財難合看。就收入來源、成本、交易與回收風險而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把舉眼見三台與流通占斷失物難得合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把鐵船渡江海與流通占斷病多端合看。就病勢變化、診療、休養與危險徵象而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "總論": "本籤以風浪見台為總軸。鐵船渡江海先定局勢，舉眼見三台交代收束；流通短斷又記運途乖。因此總體評為偏弱，關鍵不是籤名好壞，而是是否符合如鐵船遇浪，眼前多阻，貴人較晚出現。", "婚姻": "問婚姻時，須把若遇陰崖處與流通占斷婚姻難合看。就婚約、家庭共識、責任與長期相處而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把舉眼見三台與流通占斷貴人緩合看。就貴人、小人、互信與溝通界線而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把鐵船渡江海與流通占斷貴人緩合看。就雙方意願、承諾、互動與情緒安全而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把一陣風浪來與流通占斷出外凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把若遇陰崖處與流通占斷田園凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的風浪見台脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句舉眼見三台下手：如鐵船遇浪，眼前多阻，貴人較晚出現。傳統占斷留下出外凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以鐵船渡江海辨識現況、以一陣風浪來檢查限制、以若遇陰崖處尋找轉機、以舉眼見三台設定停止或完成條件。因本籤重點是風浪見台，實際行動應符合如鐵船遇浪，眼前多阻，貴人較晚出現。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 17, "displayNo": "第17籤", "level": "吉", "title": "註生娘娘靈籤第17籤", "poem": ["兩年不豐登", "今年見太平", "久仇寃未改", "禍去福重迎"], "story": "【久困回春】農歲不豐轉為太平，屬長困後復甦；舊仇未改提醒外部改善不代表積怨自動消失。", "classicMeaning": "", "plainMeaning": "第17籤以久困回春為核心。四句依次為兩年不豐登、今年見太平、久仇寃未改、禍去福重迎。整體義理是：長期不順開始平復，舊怨仍須處理。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把兩年不豐登與流通占斷求財平合看。就職位、合作、權責與計畫推進而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把今年見太平與流通占斷求財平合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把久仇寃未改與流通占斷求財平合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把禍去福重迎與流通占斷尋物可獲合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把兩年不豐登與流通占斷求財平合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "總論": "本籤以久困回春為總軸。兩年不豐登先定局勢，禍去福重迎交代收束；流通短斷又記凡事初作平平，繼續便佳。因此總體評為吉，關鍵不是籤名好壞，而是是否符合長期不順開始平復，舊怨仍須處理。", "婚姻": "問婚姻時，須把久仇寃未改與流通占斷婚姻先凶後吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把禍去福重迎與流通占斷貴人緩合看。就貴人、小人、互信與溝通界線而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把兩年不豐登與流通占斷貴人緩合看。就雙方意願、承諾、互動與情緒安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把今年見太平與流通占斷出外平合看。就交通、方向、應期、阻滯與人身安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把久仇寃未改與流通占斷田園平合看。就居所、家庭安寧、田產與搬遷而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的久困回春脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句禍去福重迎下手：長期不順開始平復，舊怨仍須處理。傳統占斷留下凡事初作平平，繼續便佳，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以兩年不豐登辨識現況、以今年見太平檢查限制、以久仇寃未改尋找轉機、以禍去福重迎設定停止或完成條件。因本籤重點是久困回春，實際行動應符合長期不順開始平復，舊怨仍須處理。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 18, "displayNo": "第18籤", "level": "平", "title": "註生娘娘靈籤第18籤", "poem": ["貴人問前程", "而今福祿生", "若有官災至", "緊守得安寧"], "story": "【福中防災】前兩句有福祿，後兩句卻警告官災，形成吉中藏戒；因此不宜只按總等級判斷。", "classicMeaning": "", "plainMeaning": "第18籤以福中防災為核心。四句依次為貴人問前程、而今福祿生、若有官災至、緊守得安寧。整體義理是：有福祿也有官災警訊，短期可行、久作須慎。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把貴人問前程與流通占斷暫時經營好，久作則凶合看。就職位、合作、權責與計畫推進而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把而今福祿生與流通占斷求財平合看。就準備程度、評核、公平程序與臨場表現而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把若有官災至與流通占斷求財平合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把緊守得安寧與流通占斷求財平合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把貴人問前程與流通占斷求財平合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "總論": "本籤以福中防災為總軸。貴人問前程先定局勢，緊守得安寧交代收束；流通短斷又記凡事謹慎不可妄為。因此總體評為平，關鍵不是籤名好壞，而是是否符合有福祿也有官災警訊，短期可行、久作須慎。", "婚姻": "問婚姻時，須把若有官災至與流通占斷婚姻平合看。就婚約、家庭共識、責任與長期相處而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把緊守得安寧與流通占斷貴人反覆，事恐中阻合看。就貴人、小人、互信與溝通界線而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把貴人問前程與流通占斷婚姻平合看。就雙方意願、承諾、互動與情緒安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把而今福祿生與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把若有官災至與流通占斷田園平合看。就居所、家庭安寧、田產與搬遷而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的福中防災脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句緊守得安寧下手：有福祿也有官災警訊，短期可行、久作須慎。傳統占斷留下凡事謹慎不可妄為，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以貴人問前程辨識現況、以而今福祿生檢查限制、以若有官災至尋找轉機、以緊守得安寧設定停止或完成條件。因本籤重點是福中防災，實際行動應符合有福祿也有官災警訊，短期可行、久作須慎。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 19, "displayNo": "第19籤", "level": "大吉", "title": "註生娘娘靈籤第19籤", "poem": ["草木方暢茂", "春風花草香", "人生須快樂", "福壽與天長"], "story": "【春生和樂】草木春風是生長與和樂意象；福壽與天長屬祝頌語，不等於醫療上的壽命保證。", "classicMeaning": "", "plainMeaning": "第19籤以春生和樂為核心。四句依次為草木方暢茂、春風花草香、人生須快樂、福壽與天長。整體義理是：草木暢茂，宜順勢經營生活與家庭，不可妄作。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把草木方暢茂與流通占斷運途吉合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把春風花草香與流通占斷運途吉合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把人生須快樂與流通占斷求財有合看。就收入來源、成本、交易與回收風險而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把福壽與天長與流通占斷運途吉合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把草木方暢茂與流通占斷求醫吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "總論": "本籤以春生和樂為總軸。草木方暢茂先定局勢，福壽與天長交代收束；流通短斷又記運途吉。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合草木暢茂，宜順勢經營生活與家庭，不可妄作。", "婚姻": "問婚姻時，須把人生須快樂與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把福壽與天長與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把草木方暢茂與流通占斷婚姻吉合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把春風花草香與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把人生須快樂與流通占斷田園吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的春生和樂脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句福壽與天長下手：草木暢茂，宜順勢經營生活與家庭，不可妄作。傳統占斷留下凡事無妄作皆好，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以草木方暢茂辨識現況、以春風花草香檢查限制、以人生須快樂尋找轉機、以福壽與天長設定停止或完成條件。因本籤重點是春生和樂，實際行動應符合草木暢茂，宜順勢經營生活與家庭，不可妄作。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 20, "displayNo": "第20籤", "level": "大吉", "title": "註生娘娘靈籤第20籤", "poem": ["遇見太陽星", "凡事得安寧", "經求逢大吉", "爭訟得咸亨"], "story": "【太陽咸亨】太陽星象徵光明正大；咸亨可理解為皆通達，也與《易》咸、亨的吉語語感相近，但無證據表明本籤直接出自某一卦辭。", "classicMeaning": "", "plainMeaning": "第20籤以太陽咸亨為核心。四句依次為遇見太陽星、凡事得安寧、經求逢大吉、爭訟得咸亨。整體義理是：光明正大則諸事通達，功名財訟皆有利。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把遇見太陽星與流通占斷運途通合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把凡事得安寧與流通占斷運途通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把經求逢大吉與流通占斷財利多合看。就收入來源、成本、交易與回收風險而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把爭訟得咸亨與流通占斷尋物現合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把遇見太陽星與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "總論": "本籤以太陽咸亨為總軸。遇見太陽星先定局勢，爭訟得咸亨交代收束；流通短斷又記運途通。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合光明正大則諸事通達，功名財訟皆有利。", "婚姻": "問婚姻時，須把經求逢大吉與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把爭訟得咸亨與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把遇見太陽星與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把凡事得安寧與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把經求逢大吉與流通占斷田厝吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的太陽咸亨脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句爭訟得咸亨下手：光明正大則諸事通達，功名財訟皆有利。傳統占斷留下財利多，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以遇見太陽星辨識現況、以凡事得安寧檢查限制、以經求逢大吉尋找轉機、以爭訟得咸亨設定停止或完成條件。因本籤重點是太陽咸亨，實際行動應符合光明正大則諸事通達，功名財訟皆有利。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 21, "displayNo": "第21籤", "level": "偏弱", "title": "註生娘娘靈籤第21籤", "poem": ["日斜樹影動", "雨壓上苑花", "雞鳴三五夜", "祿馬水雲涯"], "story": "【水涯候時】上苑花受雨壓，與水雲涯相應；流通解把水邊、月明列為方向和時序線索。", "classicMeaning": "", "plainMeaning": "第21籤以水涯候時為核心。四句依次為日斜樹影動、雨壓上苑花、雞鳴三五夜、祿馬水雲涯。整體義理是：月明、雞鳴與水邊皆是應期線索，結果較慢。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把日斜樹影動與流通占斷求財在水邊合看。就職位、合作、權責與計畫推進而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把雨壓上苑花與流通占斷求財在水邊合看。就準備程度、評核、公平程序與臨場表現而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把雞鳴三五夜與流通占斷求財在水邊合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把祿馬水雲涯與流通占斷尋物水邊合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把日斜樹影動與流通占斷求財在水邊合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "總論": "本籤以水涯候時為總軸。日斜樹影動先定局勢，祿馬水雲涯交代收束；流通短斷又記凡事月明時方有貴人。因此總體評為偏弱，關鍵不是籤名好壞，而是是否符合月明、雞鳴與水邊皆是應期線索，結果較慢。", "婚姻": "問婚姻時，須把雞鳴三五夜與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把祿馬水雲涯與流通占斷凡事月明時方有貴人合看。就貴人、小人、互信與溝通界線而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把日斜樹影動與流通占斷凡事月明時方有貴人合看。就雙方意願、承諾、互動與情緒安全而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把雨壓上苑花與流通占斷求財在水邊合看。就交通、方向、應期、阻滯與人身安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把雞鳴三五夜與流通占斷田厝平合看。就居所、家庭安寧、田產與搬遷而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的水涯候時脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句祿馬水雲涯下手：月明、雞鳴與水邊皆是應期線索，結果較慢。傳統占斷留下凡事月明時方有貴人，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以日斜樹影動辨識現況、以雨壓上苑花檢查限制、以雞鳴三五夜尋找轉機、以祿馬水雲涯設定停止或完成條件。因本籤重點是水涯候時，實際行動應符合月明、雞鳴與水邊皆是應期線索，結果較慢。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 22, "displayNo": "第22籤", "level": "凶", "title": "註生娘娘靈籤第22籤", "poem": ["漢外黑雲飛", "雷霆霹靂推", "人心皆似鐵", "官法火爐開"], "story": "【雷霆官法】黑雲、雷霆、鐵心、火爐連續加重官法威勢，是對爭訟升高的警告；漢外可能有異文可能，保留流通本用字。", "classicMeaning": "", "plainMeaning": "第22籤以雷霆官法為核心。四句依次為漢外黑雲飛、雷霆霹靂推、人心皆似鐵、官法火爐開。整體義理是：人情冷硬、法令如爐，任何爭端都可能升高。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把漢外黑雲飛與流通占斷謀事不吉合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把雷霆霹靂推與流通占斷訟事凶合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把人心皆似鐵與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把官法火爐開與流通占斷訟事凶合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把漢外黑雲飛與流通占斷病危險合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "總論": "本籤以雷霆官法為總軸。漢外黑雲飛先定局勢，官法火爐開交代收束；流通短斷又記訟事凶。因此總體評為凶，關鍵不是籤名好壞，而是是否符合人情冷硬、法令如爐，任何爭端都可能升高。", "婚姻": "問婚姻時，須把人心皆似鐵與流通占斷婚不吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把官法火爐開與流通占斷用人凶合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把漢外黑雲飛與流通占斷婚不吉合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把雷霆霹靂推與流通占斷訟事凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把人心皆似鐵與流通占斷田厝凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的雷霆官法脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句官法火爐開下手：人情冷硬、法令如爐，任何爭端都可能升高。傳統占斷留下訟事凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以漢外黑雲飛辨識現況、以雷霆霹靂推檢查限制、以人心皆似鐵尋找轉機、以官法火爐開設定停止或完成條件。因本籤重點是雷霆官法，實際行動應符合人情冷硬、法令如爐，任何爭端都可能升高。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 23, "displayNo": "第23籤", "level": "大吉", "title": "註生娘娘靈籤第23籤", "poem": ["聖帝行符勅", "流名傳世間", "凶星盡迴避", "國泰與民安"], "story": "【符敕安民】聖帝行符敕屬道教符命與鎮護語彙；此籤未明定聖帝身分，不應擅自認定為某位神明。", "classicMeaning": "", "plainMeaning": "第23籤以符敕安民為核心。四句依次為聖帝行符勅、流名傳世間、凶星盡迴避、國泰與民安。整體義理是：秩序恢復、凶星退避，整體利公正與安定。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把聖帝行符勅與流通占斷求名有合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把流名傳世間與流通占斷求名有合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把凶星盡迴避與流通占斷求財平合看。就收入來源、成本、交易與回收風險而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把國泰與民安與流通占斷求財平合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把聖帝行符勅與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "總論": "本籤以符敕安民為總軸。聖帝行符勅先定局勢，國泰與民安交代收束；流通短斷又記運途通。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合秩序恢復、凶星退避，整體利公正與安定。", "婚姻": "問婚姻時，須把凶星盡迴避與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把國泰與民安與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把聖帝行符勅與流通占斷婚姻吉合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把流名傳世間與流通占斷行人未至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把凶星盡迴避與流通占斷田厝皆吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的符敕安民脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句國泰與民安下手：秩序恢復、凶星退避，整體利公正與安定。傳統占斷留下求財平，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以聖帝行符勅辨識現況、以流名傳世間檢查限制、以凶星盡迴避尋找轉機、以國泰與民安設定停止或完成條件。因本籤重點是符敕安民，實際行動應符合秩序恢復、凶星退避，整體利公正與安定。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 24, "displayNo": "第24籤", "level": "大吉", "title": "註生娘娘靈籤第24籤", "poem": ["見官終有理", "占病定無憂", "求財多得遂", "凡事盡綢繆"], "story": "【綢繆得遂】綢繆見於未雨綢繆的語義系統，指事前準備；全詩直接列官、病、財三類結果。", "classicMeaning": "", "plainMeaning": "第24籤以綢繆得遂為核心。四句依次為見官終有理、占病定無憂、求財多得遂、凡事盡綢繆。整體義理是：事先準備充分，官病財皆可穩定處理。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把見官終有理與流通占斷謀事成合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把占病定無憂與流通占斷運途通合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把求財多得遂與流通占斷求財吉合看。就收入來源、成本、交易與回收風險而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把凡事盡綢繆與流通占斷訴訟吉合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把見官終有理與流通占斷病可癒合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "總論": "本籤以綢繆得遂為總軸。見官終有理先定局勢，凡事盡綢繆交代收束；流通短斷又記運途通。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合事先準備充分，官病財皆可穩定處理。", "婚姻": "問婚姻時，須把求財多得遂與流通占斷訴訟吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把凡事盡綢繆與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把見官終有理與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把占病定無憂與流通占斷出外吉合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把求財多得遂與流通占斷田厝吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的綢繆得遂脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句凡事盡綢繆下手：事先準備充分，官病財皆可穩定處理。傳統占斷留下訴訟吉，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以見官終有理辨識現況、以占病定無憂檢查限制、以求財多得遂尋找轉機、以凡事盡綢繆設定停止或完成條件。因本籤重點是綢繆得遂，實際行動應符合事先準備充分，官病財皆可穩定處理。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 25, "displayNo": "第25籤", "level": "凶", "title": "註生娘娘靈籤第25籤", "poem": ["無翼豈自飛", "無足豈自行", "遠來皆不泰", "恐怕向前程"], "story": "【無翼難飛】無翼不飛、無足不行是必要條件的反問，比喻資源與能力不足時不可強進。", "classicMeaning": "", "plainMeaning": "第25籤以無翼難飛為核心。四句依次為無翼豈自飛、無足豈自行、遠來皆不泰、恐怕向前程。整體義理是：缺乏必要條件，遠行與強進都不合時。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把無翼豈自飛與流通占斷謀事危合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把無足豈自行與流通占斷貴人暗合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把遠來皆不泰與流通占斷求財難合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把恐怕向前程與流通占斷失物難尋合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把無翼豈自飛與流通占斷求醫凶合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "總論": "本籤以無翼難飛為總軸。無翼豈自飛先定局勢，恐怕向前程交代收束；流通短斷又記百事須退不宜進。因此總體評為凶，關鍵不是籤名好壞，而是是否符合缺乏必要條件，遠行與強進都不合時。", "婚姻": "問婚姻時，須把遠來皆不泰與流通占斷貴人暗合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把恐怕向前程與流通占斷貴人暗合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把無翼豈自飛與流通占斷貴人暗合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把無足豈自行與流通占斷行人未至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把遠來皆不泰與流通占斷田厝吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的無翼難飛脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句恐怕向前程下手：缺乏必要條件，遠行與強進都不合時。傳統占斷留下貴人暗，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以無翼豈自飛辨識現況、以無足豈自行檢查限制、以遠來皆不泰尋找轉機、以恐怕向前程設定停止或完成條件。因本籤重點是無翼難飛，實際行動應符合缺乏必要條件，遠行與強進都不合時。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 26, "displayNo": "第26籤", "level": "凶", "title": "註生娘娘靈籤第26籤", "poem": ["畫燭當風炎", "無風燭自搖", "臨官不用早", "花發落地空"], "story": "【風燭花空】風中燭與自搖燭皆指不穩；花發落空表示表面有成、結果仍可能失落。", "classicMeaning": "", "plainMeaning": "第26籤以風燭花空為核心。四句依次為畫燭當風炎、無風燭自搖、臨官不用早、花發落地空。整體義理是：局勢內外皆不穩，表面開花也可能落空。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把畫燭當風炎與流通占斷運途艱難合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把無風燭自搖與流通占斷運途艱難合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把臨官不用早與流通占斷物價下跌合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把花發落地空與流通占斷失物無合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把畫燭當風炎與流通占斷老人病危合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "總論": "本籤以風燭花空為總軸。畫燭當風炎先定局勢，花發落地空交代收束；流通短斷又記運途艱難。因此總體評為凶，關鍵不是籤名好壞，而是是否符合局勢內外皆不穩，表面開花也可能落空。", "婚姻": "問婚姻時，須把臨官不用早與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把花發落地空與流通占斷訴訟凶合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把畫燭當風炎與流通占斷婚姻凶合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把無風燭自搖與流通占斷行人未至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把臨官不用早與流通占斷田厝凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的風燭花空脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句花發落地空下手：局勢內外皆不穩，表面開花也可能落空。傳統占斷留下訴訟凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以畫燭當風炎辨識現況、以無風燭自搖檢查限制、以臨官不用早尋找轉機、以花發落地空設定停止或完成條件。因本籤重點是風燭花空，實際行動應符合局勢內外皆不穩，表面開花也可能落空。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 27, "displayNo": "第27籤", "level": "凶", "title": "註生娘娘靈籤第27籤", "poem": ["凡事能見消", "家門破憂災", "遠行宜且止", "福去頻禍來"], "story": "【家門多災】家門破憂災與福去禍來皆屬直接警語，沒有可靠理由替它加上轉吉人物故事。", "classicMeaning": "", "plainMeaning": "第27籤以家門多災為核心。四句依次為凡事能見消、家門破憂災、遠行宜且止、福去頻禍來。整體義理是：宜停遠行、收縮計畫，先處理家庭與安全。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把凡事能見消與流通占斷運途坎坷合看。就職位、合作、權責與計畫推進而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把家門破憂災與流通占斷運途坎坷合看。就準備程度、評核、公平程序與臨場表現而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把遠行宜且止與流通占斷求財無合看。就收入來源、成本、交易與回收風險而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把福去頻禍來與流通占斷失物難尋合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把凡事能見消與流通占斷求醫不吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "總論": "本籤以家門多災為總軸。凡事能見消先定局勢，福去頻禍來交代收束；流通短斷又記運途坎坷。因此總體評為凶，關鍵不是籤名好壞，而是是否符合宜停遠行、收縮計畫，先處理家庭與安全。", "婚姻": "問婚姻時，須把遠行宜且止與流通占斷婚姻凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把福去頻禍來與流通占斷訴訟凶合看。就貴人、小人、互信與溝通界線而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把凡事能見消與流通占斷婚姻凶合看。就雙方意願、承諾、互動與情緒安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把家門破憂災與流通占斷出外凶合看。就交通、方向、應期、阻滯與人身安全而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把遠行宜且止與流通占斷田園凶合看。就居所、家庭安寧、田產與搬遷而言，此項屬凶：阻礙明顯，宜停止擴張並先避險。這個判斷源於本籤的家門多災脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句福去頻禍來下手：宜停遠行、收縮計畫，先處理家庭與安全。傳統占斷留下訴訟凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以凡事能見消辨識現況、以家門破憂災檢查限制、以遠行宜且止尋找轉機、以福去頻禍來設定停止或完成條件。因本籤重點是家門多災，實際行動應符合宜停遠行、收縮計畫，先處理家庭與安全。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 28, "displayNo": "第28籤", "level": "吉", "title": "註生娘娘靈籤第28籤", "poem": ["葵花謝又開", "遠者去重來", "任他險不險", "任災不見災"], "story": "【葵花再開】葵花謝而復開，是再生、重來、初敗後成的象徵；但流通短斷也保留久病難斷根等限制。", "classicMeaning": "", "plainMeaning": "第28籤以葵花再開為核心。四句依次為葵花謝又開、遠者去重來、任他險不險、任災不見災。整體義理是：初敗後成、去者復來，但舊疾與根本問題未必全除。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把葵花謝又開與流通占斷運途無礙合看。就職位、合作、權責與計畫推進而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把遠者去重來與流通占斷運途無礙合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把任他險不險與流通占斷新婚凶合看。就收入來源、成本、交易與回收風險而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把任災不見災與流通占斷新婚凶合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把葵花謝又開與流通占斷病不畏合看。就病勢變化、診療、休養與危險徵象而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "總論": "本籤以葵花再開為總軸。葵花謝又開先定局勢，任災不見災交代收束；流通短斷又記運途無礙。因此總體評為吉，關鍵不是籤名好壞，而是是否符合初敗後成、去者復來，但舊疾與根本問題未必全除。", "婚姻": "問婚姻時，須把任他險不險與流通占斷新婚凶合看。就婚約、家庭共識、責任與長期相處而言，此項屬偏弱：條件不足，守成與等待比硬推有利。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把任災不見災與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把葵花謝又開與流通占斷新婚凶合看。就雙方意願、承諾、互動與情緒安全而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把遠者去重來與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把任他險不險與流通占斷田厝平合看。就居所、家庭安寧、田產與搬遷而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的葵花再開脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句任災不見災下手：初敗後成、去者復來，但舊疾與根本問題未必全除。傳統占斷留下新婚凶，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以葵花謝又開辨識現況、以遠者去重來檢查限制、以任他險不險尋找轉機、以任災不見災設定停止或完成條件。因本籤重點是葵花再開，實際行動應符合初敗後成、去者復來，但舊疾與根本問題未必全除。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 29, "displayNo": "第29籤", "level": "大吉", "title": "註生娘娘靈籤第29籤", "poem": ["崑崙高峰上", "遇見呂仙翁", "賜伊財寶物", "凡事得禎祥"], "story": "【仙翁賜福】崑崙是神話仙境與西方高山意象；呂仙翁通常指呂洞賓。此為宗教傳說性神仙敘事，不能當歷史會遇。", "classicMeaning": "", "plainMeaning": "第29籤以仙翁賜福為核心。四句依次為崑崙高峰上、遇見呂仙翁、賜伊財寶物、凡事得禎祥。整體義理是：遇高明貴人而得財祿，屬明確吉象。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把崑崙高峰上與流通占斷經營吉合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把遇見呂仙翁與流通占斷貴人現合看。就準備程度、評核、公平程序與臨場表現而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把賜伊財寶物與流通占斷經營吉合看。就收入來源、成本、交易與回收風險而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把凡事得禎祥與流通占斷貴人現合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把崑崙高峰上與流通占斷求醫吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "總論": "本籤以仙翁賜福為總軸。崑崙高峰上先定局勢，凡事得禎祥交代收束；流通短斷又記貴人現。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合遇高明貴人而得財祿，屬明確吉象。", "婚姻": "問婚姻時，須把賜伊財寶物與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把凡事得禎祥與流通占斷貴人現合看。就貴人、小人、互信與溝通界線而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把崑崙高峰上與流通占斷貴人現合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把遇見呂仙翁與流通占斷行人至合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把賜伊財寶物與流通占斷田厝吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的仙翁賜福脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句凡事得禎祥下手：遇高明貴人而得財祿，屬明確吉象。傳統占斷留下貴人現，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以崑崙高峰上辨識現況、以遇見呂仙翁檢查限制、以賜伊財寶物尋找轉機、以凡事得禎祥設定停止或完成條件。因本籤重點是仙翁賜福，實際行動應符合遇高明貴人而得財祿，屬明確吉象。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}},
{"no": 30, "displayNo": "第30籤", "level": "大吉", "title": "註生娘娘靈籤第30籤", "poem": ["參拾增一枝", "未來我先知", "萬事皆合意", "添油正合宜"], "story": "【添油增福】參拾是三十的異體寫法。增一枝可能指再求一籤確認細節，也可能只是以末籤祝福收束；添油是民間寺廟供燈還願習俗。", "classicMeaning": "", "plainMeaning": "第30籤以添油增福為核心。四句依次為參拾增一枝、未來我先知、萬事皆合意、添油正合宜。整體義理是：第三十籤以祝福收束，宜感恩還願並再確認細節。流通短斷涵蓋財、婚、病、訟、行人、田宅等事項，但這些屬民俗占斷紀錄，不能直接取代醫療、法律或財務判斷。", "categoryReadings": {"事業": "問事業時，須把參拾增一枝與流通占斷謀事成合看。就職位、合作、權責與計畫推進而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "考試": "問考試時，須把未來我先知與流通占斷訴訟吉合看。就準備程度、評核、公平程序與臨場表現而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "求財": "問求財時，須把萬事皆合意與流通占斷求財有合看。就收入來源、成本、交易與回收風險而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "失物": "問失物時，須把添油正合宜與流通占斷訴訟吉合看。就遺失時間、位置、移動路徑與尋回時效而言，此項屬平：吉凶並見，結果取決於時機與準備。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "健康": "問健康時，須把參拾增一枝與流通占斷訴訟吉合看。就病勢變化、診療、休養與危險徵象而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "總論": "本籤以添油增福為總軸。參拾增一枝先定局勢，添油正合宜交代收束；流通短斷又記訴訟吉。因此總體評為大吉，關鍵不是籤名好壞，而是是否符合第三十籤以祝福收束，宜感恩還願並再確認細節。", "婚姻": "問婚姻時，須把萬事皆合意與流通占斷婚姻吉合看。就婚約、家庭共識、責任與長期相處而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "人際": "問人際時，須把添油正合宜與流通占斷貴人遲合看。就貴人、小人、互信與溝通界線而言，此項屬吉：趨勢向好，按正道推進可得成果。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "感情": "問感情時，須把參拾增一枝與流通占斷貴人遲合看。就雙方意願、承諾、互動與情緒安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "出行": "問出行時，須把未來我先知與流通占斷行人緩合看。就交通、方向、應期、阻滯與人身安全而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "家宅": "問家宅時，須把萬事皆合意與流通占斷田厝吉合看。就居所、家庭安寧、田產與搬遷而言，此項屬大吉：條件成熟，守正行動可望明顯有成。這個判斷源於本籤的添油增福脈絡，不是由總籤等直接複製。", "修心建議": "修心應從詩句添油正合宜下手：第三十籤以祝福收束，宜感恩還願並再確認細節。傳統占斷留下宜於神前添油，反映此籤要求把祈願落實為節制、守信或避惡，而非只等待外力改運。"}, "actionAdvice": ["先確認所問事項與期限，再以參拾增一枝辨識現況、以未來我先知檢查限制、以萬事皆合意尋找轉機、以添油正合宜設定停止或完成條件。因本籤重點是添油增福，實際行動應符合第三十籤以祝福收束，宜感恩還願並再確認細節。"], "warnings": ["占卜結果僅供參考"], "sourceIds": ["ai_guide"], "dataQuality": {"poemChecked": true, "meaningRewritten": true, "traditionalChineseChecked": true}}
];

